mapper.select:
SELECT T1.ID AS COURSE_ID , T2.ID AS NOTICE_ID , T2.TITLE , T2.INS_ID AS WRITER , T2.INS_DT AS CREATED_AT , T2.VIEW_COUNT , T2.VIEW_COUNT AS VIEW_COUNT FROM COURSES T1 INNER JOIN NOTICES T2 ON T2.COURSE_ID = T1.ID WHERE T1.ID = #{courseId}
AND T2.TITLE LIKE CONCAT('%', #{req.keyword}, '%')
AND T2.CONTENT LIKE CONCAT('%', #{req.keyword}, '%')
AND T2.INS_ID LIKE CONCAT('%', #{req.keyword}, '%')
AND (T2.TITLE LIKE CONCAT('%', #{req.keyword}, '%') OR T2.CONTENT LIKE CONCAT('%', #{req.keyword}, '%'))
ORDER BY T2.ID DESC LIMIT #{req.size} OFFSET #{req.offset}

mapper.update:
